struct Message { data: Vec<u8> }

fn send_message(msg: Message) {
    let len = msg.data.len();
    if len >= 20 {
        let slice = &msg.data[10..20];
        println!("Message length: {}
Data: {:?}", slice.len(), slice);
    } else {
        eprintln!("Error: data too short to send message");
    }
}

fn main() {
    let msg = Message { data: vec![1, 2, 3] };
    send_message(msg);
}

